import os
import json
import argparse
import heapq
import numpy as np
from cogniplan_env import ExplorationEnv


def build_graph(nodes):
    coord_to_idx = {}
    coords = []
    for i, n in enumerate(nodes):
        c = tuple(np.round(np.array(n['coords']), 2))
        coord_to_idx[c] = i
        coords.append(np.array(n['coords'], dtype=float))
    adj = [[] for _ in range(len(nodes))]
    for i, n in enumerate(nodes):
        for nb in n.get('neighbors', []):
            ct = tuple(np.round(np.array(nb), 2))
            j = coord_to_idx.get(ct)
            if j is not None and j != i:
                d = float(np.linalg.norm(coords[i] - coords[j]))
                adj[i].append((j, d))
    return coord_to_idx, coords, adj


def dijkstra(adj, start):
    n = len(adj)
    dist = [float('inf')] * n
    prev = [-1] * n
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u]:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def path_first_step(prev, start, target):
    if target == start:
        return target
    if prev[target] == -1:
        return target
    cur = target
    while prev[cur] != start and prev[cur] != -1:
        cur = prev[cur]
    return cur


def plan_episode(map_path, max_steps=128):
    env = ExplorationEnv(map_path=map_path)
    obs = env.reset()

    for step in range(max_steps):
        try:
            neighbors = obs['neighbors']
            nodes = obs['nodes']
        except Exception:
            break
        if not neighbors or not nodes:
            break
        robot = np.array(obs['robot_pos'], dtype=float)

        coord_to_idx, coords, adj = build_graph(nodes)
        if len(coords) == 0:
            break
        dists_to_robot = [np.linalg.norm(c - robot) for c in coords]
        start_idx = int(np.argmin(dists_to_robot))
        dist, prev = dijkstra(adj, start_idx)

        # Score: utility^1.3 / (distance + 1) — biases toward higher-utility targets,
        # reducing zigzag toward small-utility-near nodes.
        scored = []
        for i, nd in enumerate(nodes):
            if i == start_idx:
                continue
            u = nd.get('utility', 0)
            if u <= 0:
                continue
            d = dist[i]
            if d == float('inf'):
                continue
            score = (u ** 1.3) / (d + 1.0)
            scored.append((score, i, u, d))
        scored.sort(reverse=True)

        chosen = None
        if scored:
            target_idx = scored[0][1]
            next_idx = path_first_step(prev, start_idx, target_idx)
            next_coord = coords[next_idx]
            chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
        else:
            # No utility>0 reachable. Go to nearest unvisited node via shortest path.
            best_d = float('inf')
            best_idx = -1
            for i, nd in enumerate(nodes):
                if i == start_idx:
                    continue
                if nd.get('visited', False):
                    continue
                d = dist[i]
                if d < best_d and d > 0:
                    best_d = d
                    best_idx = i
            if best_idx >= 0:
                next_idx = path_first_step(prev, start_idx, best_idx)
                next_coord = coords[next_idx]
                chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
            else:
                chosen = neighbors[0]

        try:
            obs, info = env.step(chosen)
        except Exception as e:
            break
        if info.get('done', False):
            break

    metrics = env.get_metrics()
    return metrics


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--data_path', required=True)
    ap.add_argument('--checkpoint', required=False, default=None)
    ap.add_argument('--output', required=True)
    args = ap.parse_args()

    cfg_path = os.path.join(args.data_path, 'eval_config.json')
    episodes = []
    if os.path.exists(cfg_path):
        try:
            with open(cfg_path) as f:
                cfg = json.load(f)
            if isinstance(cfg, dict):
                episodes = cfg.get('episodes') or cfg.get('maps') or cfg.get('eval_maps') or []
            elif isinstance(cfg, list):
                episodes = cfg
        except Exception:
            episodes = []

    maps_dir = os.path.join(args.data_path, 'maps_eval')
    if not episodes and os.path.isdir(maps_dir):
        for sub in sorted(os.listdir(maps_dir)):
            sd = os.path.join(maps_dir, sub)
            if os.path.isdir(sd):
                for fn in sorted(os.listdir(sd)):
                    if fn.lower().endswith(('.png', '.jpg', '.jpeg')):
                        episodes.append({'map_path': f'{sub}/{fn}', 'env_type': sub})

    per_episode = []
    per_type = {}
    for ep in episodes:
        mp = ep.get('map_path') if isinstance(ep, dict) else ep
        et = ep.get('env_type') if isinstance(ep, dict) else 'unknown'
        if not mp:
            continue
        full = mp if os.path.isabs(mp) else os.path.join(maps_dir, mp)
        try:
            m = plan_episode(full)
            success = 1 if m.get('explored_rate', 0) > 0.9999 else 0
            d = float(m.get('travel_distance', 0))
            er = float(m.get('explored_rate', 0))
        except Exception:
            success, d, er = 0, 0.0, 0.0
        rec = {'map_path': mp, 'env_type': et, 'success': success,
               'travel_distance': d, 'explored_rate': er}
        per_episode.append(rec)
        per_type.setdefault(et, []).append(rec)

    total = len(per_episode)
    explored = float(np.mean([r['explored_rate'] for r in per_episode])) if per_episode else 0.0
    succ_eps = [r for r in per_episode if r['success'] == 1]
    travel = float(np.mean([r['travel_distance'] for r in succ_eps])) if succ_eps else 0.0
    success_rate = (sum(r['success'] for r in per_episode) / total) if total else 0.0

    pt = {}
    for et, recs in per_type.items():
        sr = [r for r in recs if r['success'] == 1]
        pt[et] = {
            'explored_rate': float(np.mean([r['explored_rate'] for r in recs])) if recs else 0.0,
            'travel_distance': float(np.mean([r['travel_distance'] for r in sr])) if sr else 0.0,
            'success_rate': float(np.mean([r['success'] for r in recs])) if recs else 0.0,
        }

    out = {
        'explored_rate': explored,
        'travel_distance': travel,
        'success_rate': success_rate,
        'per_episode': per_episode,
        'per_type': pt,
        'total_episodes': total,
    }
    os.makedirs(os.path.dirname(os.path.abspath(args.output)) or '.', exist_ok=True)
    with open(args.output, 'w') as f:
        json.dump(out, f)


if __name__ == '__main__':
    main()
